sp_angular_provider.script:
function scmFlyover(spUtil, $timeout, $compile, $location) {
    const CLOSE_TIMEOUT = 300;
    const OPEN_THROTTLE_TIMEOUT = 500;

    return function (widgetId, scopeCtrl) {
        this.flyover = {
            flyoverId: spUtil.createUid("xxxx-xxxx"),
            transactionId: "",
            scope: scopeCtrl,
            widgetId: widgetId,
            title: "",
            subTitle: "",
            hasFullClass: false,
            options: {},
            isOpen: false,
            functionOnOpen: null,
            functionOnClose: null,
            width: 85,
            appendToBody: false,
        };

        let that = this;
        that.childScope = null;
        that.openThrottlePromise = null;
        that.closePromise = null;
        that.openSequence = 0;

        that.unregisterCloseTriggered = scopeCtrl.$on(
            "scmFlyover-close-triggered-" + this.flyover.flyoverId,
            function (e) {
                close.apply(that);
            },
        );

        that.open = open;
        that.close = close;
        that.setOptions = setOptions;
        that.setTitle = setTitle;
        that.setSubTitle = setSubTitle;
        that.onOpen = onOpen;
        that.onClose = onClose;
        that.hasFullClass = hasFullClass;
        that.setFlyoverWidth = setFlyoverWidth;
        that.setAppendToBody = setAppendToBody;
        that.setWidgetId = setWidgetId;
        that.isOpen = isOpen;
        that.setTransactionId = setTransactionId;
        that.destroy = destroy;

        return that;
    };

    function open() {
        let that = this;

        if (that.flyover.isOpen || that.openThrottlePromise) {
            return new Promise(function (resolve) {
                resolve();
            });
        }

        if (that.closePromise) {
            $timeout.cancel(that.closePromise);
            that.closePromise = null;
        }

        that.openThrottlePromise = $timeout(function () {
            that.openThrottlePromise = null;
        }, OPEN_THROTTLE_TIMEOUT);

        that.flyover.isOpen = true;
        that.openSequence += 1;
        const requestSequence = that.openSequence;

        that.childScope = that.flyover.scope.$new(true);

        return spUtil
            .get("scm-flyover", {
                widgetUid: that.flyover.flyoverId,
                widgetId: that.flyover.widgetId,
                transactionId: that.flyover.transactionId,
                title: that.flyover.title,
                subTitle: that.flyover.subTitle,
                hasFullClass: that.flyover.hasFullClass,
                width: that.flyover.width,
                widgetOptions: that.flyover.options,
            })
            .then(function (response) {
                if (
                    !that.flyover.isOpen ||
                    requestSequence !== that.openSequence
                ) {
                    return that;
                }

                if (that.flyover.functionOnOpen) {
                    _executeCallback(that, that.flyover.functionOnOpen);
                }

                _generateWidgetHTML(that, response, that.flyover.scope);

                return that;
            });
    }

    function setTitle(title) {
        this.flyover.title = title;
    }

    function setTransactionId(transactionId) {
        this.flyover.transactionId = transactionId;
    }

    function setSubTitle(subTitle) {
        this.flyover.subTitle = subTitle;
    }

    function hasFullClass(hasFullClass) {
        this.flyover.hasFullClass = hasFullClass;
    }

    function _generateWidgetHTML(that, response, scope) {
        let snippetHTML =
            "<div ng-attr-id='flyoverContainer-{{flyOverId}}'>" +
            "  <div ng-repeat='widget in widgetsFly'>" +
            "    <sp-widget widget='widget'></sp-widget>" +
            " </div>" +
            "</div>";

        if (
            !document.querySelector(
                "#flyoverContainer-" + that.flyover.flyoverId,
            )
        ) {
            that.childScope.widgetsFly = [response];
            that.childScope.flyOverId = that.flyover.flyoverId;

            let compiledSnippetHTML = $compile(snippetHTML)(that.childScope);

            if (that.flyover.appendToBody) {
                $("body").append(compiledSnippetHTML);
            } else {
                let widgetContainers = document.querySelectorAll(
                    ".v" + scope.widget.sys_id,
                );
                let lastWidgetContainer =
                    widgetContainers[widgetContainers.length - 1];

                angular
                    .element(lastWidgetContainer)
                    .append(compiledSnippetHTML);
            }
        }
    }

    function setOptions(optionsObject) {
        this.flyover.options = optionsObject;
    }

    function onOpen(functionToBeExecuted) {
        this.flyover.functionOnOpen =
            typeof functionToBeExecuted === "function"
                ? functionToBeExecuted
                : null;

        if (functionToBeExecuted && !this.flyover.functionOnOpen) {
            console.warn(
                "scmFlyover.onOpen expects a function callback. Ignoring invalid callback.",
            );
        }
    }

    function onClose(functionToBeExecuted) {
        this.flyover.functionOnClose =
            typeof functionToBeExecuted === "function"
                ? functionToBeExecuted
                : null;

        if (functionToBeExecuted && !this.flyover.functionOnClose) {
            console.warn(
                "scmFlyover.onClose expects a function callback. Ignoring invalid callback.",
            );
        }
    }

    function _executeCallback(that, callback) {
        if (typeof callback === "function") {
            callback(that);
        }
    }

    function setFlyoverWidth(width) {
        this.flyover.width = width;
    }

    function setAppendToBody(v) {
        this.flyover.appendToBody = v;
    }

    function setWidgetId(id) {
        this.flyover.widgetId = id;
    }

    function close() {
        let that = this;

        that.flyover.isOpen = false;
        that.openSequence += 1;

        if (that.closePromise) {
            return that.closePromise;
        }

        that.closePromise = $timeout(function () {
            teardownFlyover(that, true);
            that.closePromise = null;
        }, CLOSE_TIMEOUT);

        return that.closePromise;
    }

    function isOpen() {
        return this.flyover.isOpen;
    }

    function teardownFlyover(that, executeOnClose) {
        if (that.childScope) {
            that.childScope.$destroy();
            that.childScope = null;
        }

        let widgetElement = document.querySelector(
            "#flyoverContainer-" + that.flyover.flyoverId,
        );
        if (widgetElement) {
            widgetElement.remove();
        }

        if (executeOnClose && that.flyover.functionOnClose) {
            _executeCallback(that, that.flyover.functionOnClose);
        }
    }

    function destroy() {
        if (this.openThrottlePromise) {
            $timeout.cancel(this.openThrottlePromise);
            this.openThrottlePromise = null;
        }

        if (this.closePromise) {
            $timeout.cancel(this.closePromise);
            this.closePromise = null;
        }

        this.flyover.isOpen = false;
        this.openSequence += 1;
        teardownFlyover(this, false);

        if (typeof this.unregisterCloseTriggered === "function") {
            this.unregisterCloseTriggered();
            this.unregisterCloseTriggered = null;
        }
    }
}
